LAYER
	NAME "sector"
	GROUP "MPE"
	TYPE polygon
	PROCESSING "LABEL_NO_CLIP=1"
	STATUS on
	DATA "geom FROM (SELECT gid, cod_sector, id_ubigeo, id_sector, ROUND(area_grafi::numeric, 2) AS area_grafi, geom FROM geo.tg_sector) as allpa using unique gid using srid=32719"
	INCLUDE "configuracion/postgresql_allpa.map"
	PROJECTION
		"init=epsg:32719"
	END
	CLASSITEM "gid"
	LABELITEM "cod_sector"
	METADATA
		"wms_group_title" "MPE"
		"queryable" "true"
		"wms_metadataurl_href" ""
		"wms_metadataurl_format" "text/xml"
		"wms_metadataurl_type" "TC211"
		"wms_title" "Sector"
		"wms_abstract" "Sector || Municipalidad Provincial de Espinar - Cusco :: Perú"
		"wms_dataurl" ""
		"wms_dataurl_format" "text/html"
		"wms_dataurl_href" ""
		"wms_credit" "Kaypacha"
		"wms_extent" "178070.01586802542 8501210.991231522 184071.98480267922 8503438.897198547"
		"wms_srs" "EPSG:32719"
		"wms_include_items" "all"
		"wms_exclude_items" "gid"
	END
	CLASS
		NAME "Sector"
		EXPRESSION /./
		STYLE
			COLOR -1 -1 -1
			OUTLINECOLOR 153 0 204
			WIDTH 2
		END
		LABEL
			COLOR 153 0 204
			FONT "Roboto"
			TYPE truetype
			SIZE 15
			POSITION cc
			PARTIALS false
		END
	END
END # Layer